request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?tablePkg ?tablePkgName ?parent ?parentName ?entry ?entryName WHERE {
  ?tablePkg rdf:type vocab:package ;
            vocab:NamedElement_name ?tablePkgName .
  FILTER(CONTAINS(LCASE(STR(?tablePkgName)), LCASE("wavefront%20calibration%20lookup%20table")))

  OPTIONAL {
    ?tablePkg vocab:Element_owner ?parent .
    OPTIONAL { ?parent vocab:NamedElement_name ?parentName . }
  }

  OPTIONAL {
    ?tablePkg vocab:Package_packagedElement+ ?entry .
    OPTIONAL { ?entry vocab:NamedElement_name ?entryName . }
  }
}
LIMIT 25
